import { useState } from "react";
import "./styles/AdminManageLibrarians.css";
import api from "../api/axios";

function AdminManageLibrarians() {
  const [librarians, setLibrarians] = useState([
    { name: "Alice", genre: "Fantasy" },
    { name: "Bob", genre: "Literature" },
    { name: "Clara", genre: "Technology" },
  ]);

  const genres = [
    "Fantasy",
    "Literature",
    "Business",
    "Technology",
    "History",
    "Science",
    "Psychology",
    "Philosophy",
    "Romance",
    "Mystery",
    "Horror",
  ];

  const updateGenre = (index, newGenre) => {
    const updated = [...librarians];
    updated[index].genre = newGenre;
    setLibrarians(updated);
  };

  const removeLibrarian = (index) => {
    const updated = librarians.filter((_, i) => i !== index);
    setLibrarians(updated);
  };

  return (
    <div className="admin-librarians-page">
      <h1 className="admin-title">Manage Librarians</h1>

      <div className="librarian-list">
        {librarians.map((lib, index) => (
          <div className="librarian-card" key={index}>
            <div className="lib-info">
              <h3>{lib.name}</h3>
              <p>Genre: {lib.genre}</p>
            </div>

            <select
              value={lib.genre}
              onChange={(e) => updateGenre(index, e.target.value)}
            >
              {genres.map((g) => (
                <option key={g}>{g}</option>
              ))}
            </select>

            <button
              className="remove-btn"
              onClick={() => removeLibrarian(index)}
            >
              Remove
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default AdminManageLibrarians;
